#include <numeric>
#include <bits/stdc++.h>
using namespace std;
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};
class Solution {
public:
    vector<int> mergeTrees(TreeNode* t1, TreeNode* t2) {
        vector<int> res;
        dfs(t1, res);
        dfs(t2, res);
        sort(res.begin(), res.end());
        return res;
    }
    void dfs(TreeNode* node, vector<int>& res) {
        if (!node) return;
        res.push_back(node->val);
        dfs(node->left, res);
        dfs(node->right, res);
    }
};
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n1;
    cin >> n1;
    TreeNode* nodes1[10000];
    for (int i = 0; i < n1; i++) {
        int val, left, right;
        cin >> val >> left >> right;
        nodes1[i] = new TreeNode(val);
        if (left != -1) nodes1[i]->left = nodes1[left];
        if (right != -1) nodes1[i]->right = nodes1[right];
    }
    TreeNode* t1 = nodes1[0];
    int n2;
    cin >> n2;
    TreeNode* nodes2[10000];
    for (int i = 0; i < n2; i++) {
        int val, left, right;
        cin >> val >> left >> right;
        nodes2[i] = new TreeNode(val);
        if (left != -1) nodes2[i]->left = nodes2[left];
        if (right != -1) nodes2[i]->right = nodes2[right];
    }
    TreeNode* t2 = nodes2[0];
    Solution sol;
    vector<int> ans = sol.mergeTrees(t1, t2);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
